import {
  geo,
  geoFromHeaders,
  isInRegion,
  geoDistance,
} from './geo'

describe('geo', () => {
  it('should extract all fields from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'New York',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'NY',
      'x-vercel-ip-latitude': '40.7128',
      'x-vercel-ip-longitude': '-74.0060',
      'x-vercel-ip-timezone': 'America/New_York',
    })
    const result = geo({ headers })

    expect(result.city).toBe('New York')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('NY')
    expect(result.latitude).toBe('40.7128')
    expect(result.longitude).toBe('-74.0060')
    expect(result.timezone).toBe('America/New_York')
  })

  it('should return undefined for all fields when no headers are present', () => {
    const headers = new Headers()
    const result = geo({ headers })

    expect(result.city).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })
})

describe('geoFromHeaders', () => {
  it('should use Vercel country header when present', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'GB',
    })
    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
  })

  it('should fall back to Cloudflare cf-ipcountry header when Vercel header is absent', () => {
    const headers = new Headers({
      'cf-ipcountry': 'DE',
    })
    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('should prefer Vercel header over Cloudflare header when both are present', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'FR',
      'cf-ipcountry': 'DE',
    })
    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('FR')
    expect(result.country).toBe('France')
  })

  it('should return undefined country for unknown country code', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'ZZ',
    })
    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })
})

describe('isInRegion', () => {
  it('should return true when countryCode matches a region in the list', () => {
    const result = isInRegion({ countryCode: 'US' }, ['US', 'CA'])
    expect(result).toBe(true)
  })

  it('should return false when countryCode does not match any region in the list', () => {
    const result = isInRegion({ countryCode: 'DE' }, ['US', 'CA'])
    expect(result).toBe(false)
  })

  it('should perform case-insensitive comparison', () => {
    expect(isInRegion({ countryCode: 'us' }, ['US'])).toBe(true)
    expect(isInRegion({ countryCode: 'US' }, ['us'])).toBe(true)
    expect(isInRegion({ countryCode: 'gb' }, ['GB', 'US'])).toBe(true)
  })

  it('should return false when geo has no countryCode', () => {
    expect(isInRegion({}, ['US', 'CA'])).toBe(false)
    expect(isInRegion({ city: 'London' }, ['US'])).toBe(false)
  })

  it('should return false for an empty regions list', () => {
    expect(isInRegion({ countryCode: 'US' }, [])).toBe(false)
  })
})

describe('geoDistance', () => {
  it('should calculate the Haversine distance from New York to London within 100km tolerance', () => {
    // New York: 40.7128°N, 74.0060°W
    // London:   51.5074°N,  0.1278°W
    // Expected great-circle distance: approximately 5570 km
    const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(Math.abs(dist - 5570)).toBeLessThan(100)
  })

  it('should return 0 for identical coordinates', () => {
    const dist = geoDistance('48.8566', '2.3522', '48.8566', '2.3522')
    expect(dist).toBe(0)
  })

  it('should return a positive distance for different coordinates', () => {
    const dist = geoDistance('35.6762', '139.6503', '-33.8688', '151.2093')
    expect(dist).toBeGreaterThan(0)
  })
})

